-- ---- Stub: lurek.thread.newThread ----------------------------------------
--@api-stub: lurek.thread.newThread
-- Run heavy work (pathfinding, world gen, parsing) off the main Lua VM so the
-- game loop never stalls waiting for a long computation to finish.
local worker_code = [[
    local ch_in  = lurek.thread.getChannel("work_in")
    local ch_out = lurek.thread.getChannel("work_out")
    while true do
        local job = ch_in:demand()
        if job == nil then break end
        ch_out:push(job * job)  -- square the number as a demo
    end
]]
local worker = lurek.thread.newThread(worker_code)

