-- ---- Stub: lurek.thread.newPool ------------------------------------------
--@api-stub: lurek.thread.newPool
-- Spawn N identical worker VMs to process a queue of jobs in parallel --
-- ideal for batch tile loading, parallel path-finding, or noise generation.
local tile_worker = [[
    local inp = lurek.thread.getChannel("tiles_in")
    local out = lurek.thread.getChannel("tiles_out")
    while true do
        local id = inp:demand()
        if id == nil then break end
        out:push({ id = id, data = "generated" })
    end
]]
local pool = lurek.thread.newPool(4, tile_worker)
print("pool of 4 tile-gen workers created")

